parameters.jsCode:
// =============================================
// STEP: Build the HTML post from the template
// =============================================
const post = $('Webhook: Receive Post Data').first().json.body;
const templateBase64 = $input.first().json.content;

// Decode the template
let html = Buffer.from(templateBase64, 'base64').toString('utf8');

// --- Helper: Format date ---
function formatDateAr(dateStr) {
  const months = ['يناير','فبراير','مارس','أبريل','مايو','يونيو','يوليو','أغسطس','سبتمبر','أكتوبر','نوفمبر','ديسمبر'];
  const d = new Date(dateStr);
  return `${d.getDate()} ${months[d.getMonth()]} ${d.getFullYear()}`;
}
function formatDateEn(dateStr) {
  const d = new Date(dateStr);
  return d.toLocaleDateString('en-US', { year:'numeric', month:'long', day:'numeric' });
}

// --- Build tags HTML ---
const tags = Array.isArray(post.tags) ? post.tags : (post.tags || '').split(',').map(t => t.trim());
const tagsStr = tags.join(', ');
const tagsHtml = tags.map(tag => `<a href="/blog/?search=${encodeURIComponent(tag)}">${tag}</a>`).join('\n                ');

// --- Slug: auto-generate if not provided ---
const slug = post.slug || post.title_en.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');

// --- WhatsApp share text ---
const waText = encodeURIComponent(`${post.title_ar} - https://techservjo.com/blog/posts/${slug}.html`);

// --- Replacements map ---
const replacements = {
  SLUG: slug,
  LANG: 'ar',
  DIR: 'rtl',
  TITLE_AR: post.title_ar || '',
  TITLE_EN: post.title_en || '',
  EXCERPT_AR: post.excerpt_ar || '',
  EXCERPT_EN: post.excerpt_en || '',
  CONTENT_AR: post.content_ar || '',
  CONTENT_EN: post.content_en || '',
  DATE: post.date || new Date().toISOString().split('T')[0],
  DATE_FORMATTED_AR: formatDateAr(post.date),
  DATE_FORMATTED_EN: formatDateEn(post.date),
  IMAGE_URL: post.image_url || 'https://images.unsplash.com/photo-1677442136019-21780ecad995?auto=format&fit=crop&q=80&w=800',
  AUTHOR: post.author || 'TechServJo Team',
  CATEGORY: post.category || 'general',
  CATEGORY_AR: post.category_ar || 'عام',
  CATEGORY_EN: post.category_en || 'General',
  READ_TIME_AR: String(post.read_time || 5),
  READ_TIME_EN: String(post.read_time || 5),
  TAGS: tagsStr,
  TAGS_HTML: tagsHtml,
  WHATSAPP_TEXT: waText
};

// Replace all placeholders
for (const [key, value] of Object.entries(replacements)) {
  html = html.replaceAll(`{{${key}}}`, value);
}

// Base64 encode for GitHub API
const htmlBase64 = Buffer.from(html).toString('base64');

// Build posts.json entry
const postEntry = {
  slug,
  title: { ar: post.title_ar, en: post.title_en },
  excerpt: { ar: post.excerpt_ar, en: post.excerpt_en },
  date: post.date || new Date().toISOString().split('T')[0],
  author: post.author || 'TechServJo Team',
  category: post.category || 'general',
  tags: tags,
  image: post.image_url || '',
  lang: ['ar', 'en'],
  readTime: { ar: post.read_time || 5, en: post.read_time || 5 }
};

return [{
  json: {
    slug,
    htmlBase64,
    postEntry,
    commitMessage: `Add blog post: ${post.title_ar} | ${post.title_en}`
  }
}];

// =============================================
// STEP: Prepend new post to posts.json index
// =============================================
const postsJsonResponse = $input.first().json;
const sha = postsJsonResponse.sha;

// Decode current posts.json
const currentContent = JSON.parse(
  Buffer.from(postsJsonResponse.content, 'base64').toString('utf8')
);

// Get the new post entry from earlier step
const newPostEntry = $('Code: Build HTML from Template').first().json.postEntry;

// Prepend new post to array (newest first)
currentContent.posts.unshift(newPostEntry);

// Re-encode
const updatedBase64 = Buffer.from(JSON.stringify(currentContent, null, 2)).toString('base64');

return [{
  json: {
    sha,
    updatedBase64,
    slug: newPostEntry.slug
  }
}];

